const shapeSortConfig = {
  tileSizePx: 72,
  dragPaddingPx: 6,
  snapTolerancePx: 16,
};

window.shapeSortConfig = shapeSortConfig;

function canGrabTile(pointer, tileRect) {
  // Increase padding on mobile for better touch accuracy
  const isMobile = window.innerWidth <= 768;
  const padding = isMobile ? 20 : shapeSortConfig.dragPaddingPx;

  return (
    pointer.x >= tileRect.left - padding &&
    pointer.x <= tileRect.right + padding &&
    pointer.y >= tileRect.top - padding &&
    pointer.y <= tileRect.bottom + padding
  );
}

window.canGrabShapeSortTile = canGrabTile;

// Update tile size in config based on screen size
function updateTileSizeForScreen() {
  if (window.innerWidth <= 480) {
    shapeSortConfig.tileSizePx = 120;
  } else if (window.innerWidth <= 768) {
    shapeSortConfig.tileSizePx = 96;
  } else {
    shapeSortConfig.tileSizePx = 72;
  }
}

// Initialize and update on resize
updateTileSizeForScreen();
window.addEventListener('resize', updateTileSizeForScreen);

